#include "curlcheck.h"

#include "urldata.h"

static CURL *easy;

static CURLcode unit_setup(void)
{
  CURLcode res = CURLE_OK;

  global_init(CURL_GLOBAL_ALL);
  easy = curl_easy_init();
  if(!easy) {
    curl_global_cleanup();
    return CURLE_OUT_OF_MEMORY;
  }
  return res;
}

static void unit_stop(void)
{
  curl_easy_cleanup(easy);
  curl_global_cleanup();
}

UNITTEST_START
{
  CURLcode ret;

  /* Test: valid priority with urgency only (u=3) */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=3");
  fail_unless(ret == CURLE_OK, "Failed to set valid h3 priority u=3");

  /* Test: valid priority with urgency and incremental (u=5,i) */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=5,i");
  fail_unless(ret == CURLE_OK, "Failed to set valid h3 priority u=5,i");

  /* Test: valid priority with urgency 0 */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  fail_unless(ret == CURLE_OK, "Failed to set valid h3 priority u=0");

  /* Test: valid priority with urgency 7 (maximum) */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  fail_unless(ret == CURLE_OK, "Failed to set valid h3 priority u=7");

  /* Test: invalid priority with urgency > 7 */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=8");
  fail_unless(ret == CURLE_BAD_FUNCTION_ARGUMENT,
              "Should reject urgency > 7");

  /* Test: invalid priority with negative urgency */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "u=-1");
  fail_unless(ret == CURLE_BAD_FUNCTION_ARGUMENT,
              "Should reject negative urgency");

  /* Test: invalid priority format (missing u=) */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, "3");
  fail_unless(ret == CURLE_BAD_FUNCTION_ARGUMENT,
              "Should reject format without u=");

  /* Test: NULL priority (should be OK, clears it) */
  ret = curl_easy_setopt(easy, CURLOPT_H3_STREAM_PRIORITY, NULL);
  fail_unless(ret == CURLE_OK, "Failed to clear h3 priority");
}
UNITTEST_STOP

